        "id": "ai_validation_guide",
        "type": "rich_text",
        "variant": "default",
        "props": {
          "eyebrow": "Strategy",
          "heading": "The Golden Rule: Validate Before You Buy",
          "body": {
            "version": 1,
            "nodes": [
              {
                "type": "paragraph",
                "text": "Before purchasing any equipment, new vending operators must validate location demand. Buying machines without a confirmed, high-traffic spot is a common mistake for beginners."
              },
              {
                "type": "heading",
                "level": 3,
                "text": "Key Demand Signals"
              },
              {
                "type": "paragraph",
                "text": "Look for these three signals to determine if a location is viable for your vending business:"
              },
              {
                "type": "list",
                "style": "bullet",
                "items": [
                  "High Foot Traffic: The sheer number of people passing by the machine.",
                  "Dwell Time: How long people stay in the vicinity of the machine.",
                  "Existing Food Options: Lack of nearby snacks or drinks increases demand."
                ]
              }
            ]
          }
        }
      },
      "sourceDocumentIds": [
        "11111111-1111-4111-8111-111111111111"
      ],
