    {
      "block": {
        "id": "ai_vending_faq",
        "type": "faq",
        "variant": "accordion",
        "props": {
          "heading": "Vending Startup FAQ",
          "items": [
            {
              "question": "When should I buy my first vending machine?",
              "answer": "You should only purchase machines after you have validated the demand at your target location. Confirming foot traffic and dwell time ensures your investment is backed by real data."
            }
          ]
        }
      },
